    print("Building Hugging Face class map... (Takes ~2 seconds)")
    hf_val_set = dataset["validation"]
    hf_by_class = defaultdict(list)

    # Map every shuffled row index to its corresponding class integer (0-999)
    for idx, item in enumerate(hf_val_set):
        hf_by_class[item["label"]].append(idx)

    print("Map built successfully!")


    # ==========================================
    # 2. THE PERCEPTUAL MATCHING FUNCTION
    # ==========================================
    def find_exact_hf_match(local_img, local_label_int, hf_dataset, hf_class_map):
        """
        Finds the exact image twin in Hugging Face by matching the underlying 
        structural composition of the photo, ignoring synthetic noise.
        """
        # Since both setups sort classes identically, the labels match perfectly
        hf_target_label = local_label_int
        
        # Step A: Prepare the local image fingerprint (convert to 32x32 grayscale float)
        if isinstance(local_img, torch.Tensor):
            # CHW -> HWC
            img_np = local_img.permute(1, 2, 0).cpu().numpy()
            # Scale to 0-255 range safely
            img_np = (img_np - img_np.min()) / (img_np.max() - img_np.min() + 1e-5)
            local_pil = Image.fromarray((img_np * 255).astype(np.uint8))
        else:
            local_pil = local_img
            
        local_fingerprint = np.array(local_pil.convert("L").resize((32, 32))).astype(float)
        
        # Step B: Search only within the 50 candidate rows belonging to that class
        best_hf_idx = None
        min_mse = float('inf')
        
        candidate_indices = hf_class_map[hf_target_label]
        for hf_idx in candidate_indices:
            hf_img = hf_dataset[hf_idx]["image"]
            # Downsample clean image to the same 32x32 grayscale space
            hf_fingerprint = np.array(hf_img.convert("L").resize((32, 32))).astype(float)
            
            # Calculate Mean Squared Error (MSE)
            mse = np.mean((local_fingerprint - hf_fingerprint) ** 2)
            
            if mse < min_mse:
                min_mse = mse
                best_hf_idx = hf_idx
                
        return best_hf_idx, min_mse

    # ==========================================
